#!/usr/bin/env node

const { execSync } = require('child_process');
const fs = require('fs');

function runCommand(command, options = {}) {
  console.log(`Executing: ${command}`);
  try {
    execSync(command, {
      stdio: 'inherit',
      ...options
    });
  } catch (error) {
    console.error(`Command failed: ${command}`);
    process.exit(1);
  }
}

// Audit dependencies first
console.log('Running security audit...');
try {
  runCommand('npm audit --audit-level=high');
} catch (error) {
  console.warn('Security vulnerabilities detected. Review before proceeding.');
}

// Install with recommended flags
console.log('Installing dependencies...');
runCommand('npm ci --ignore-scripts');

// Only run your own postinstall, not from packages
if (fs.existsSync('package.json')) {
  const pkg = JSON.parse(fs.readFileSync('package.json', 'utf8'));
  if (pkg.scripts && pkg.scripts.postinstall) {
    console.log('Running project postinstall script...');
    runCommand('npm run postinstall');
  }
}

console.log('Installation complete!');